import React from "react";
import { useNavigate } from "react-router-dom";

export default function NotFound() {
    const navigate = useNavigate();

    return (
        <div style={{
            minHeight: "100vh",
            background: "#f8f9fa",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "'Segoe UI', sans-serif",
            padding: "20px",
        }}>
            <div style={{
                textAlign: "center",
                maxWidth: 480,
                width: "100%",
            }}>

                {/* Logo */}
                <div style={{ marginBottom: 32 }}>
                    <img
                        src="/assets/images/capavate.png"
                        alt="Capavate"
                        style={{ height: 40, objectFit: "contain" }}
                        onError={(e) => { e.target.style.display = "none"; }}
                    />
                </div>

                {/* 404 Visual */}
                <div style={{
                    background: "#fff",
                    borderRadius: 20,
                    padding: "48px 40px 40px",
                    boxShadow: "0 4px 24px rgba(0,0,0,0.06)",
                    border: "1px solid #f0f0f0",
                }}>
                    {/* Big 404 */}
                    <div style={{
                        fontSize: "96px",
                        fontWeight: 800,
                        lineHeight: 1,
                        color: "#ff3e43",
                        letterSpacing: "-4px",
                        marginBottom: 4,
                        userSelect: "none",
                    }}>
                        404
                    </div>

                    {/* Divider line */}
                    <div style={{
                        width: 48,
                        height: 3,
                        background: "#ff3e43",
                        borderRadius: 2,
                        margin: "16px auto 24px",
                    }} />

                    {/* Title */}
                    <h2 style={{
                        fontSize: "1.3rem",
                        fontWeight: 700,
                        color: "#1a1a1a",
                        margin: "0 0 10px",
                    }}>
                        Page not found
                    </h2>

                    {/* Description */}
                    <p style={{
                        fontSize: "0.9rem",
                        color: "#888",
                        lineHeight: 1.6,
                        margin: "0 0 32px",
                    }}>
                        The page you're looking for doesn't exist or has been moved.
                    </p>

                    {/* Buttons */}
                    <div style={{ display: "flex", gap: 10, justifyContent: "center", flexWrap: "wrap" }}>
                        <button
                            onClick={() => navigate(-1)}
                            style={{
                                padding: "10px 22px",
                                borderRadius: 10,
                                border: "1.5px solid #e0e0e0",
                                background: "#fff",
                                color: "#444",
                                fontSize: "0.85rem",
                                fontWeight: 600,
                                cursor: "pointer",
                                transition: "all 0.2s",
                            }}
                            onMouseEnter={(e) => e.currentTarget.style.borderColor = "#ff3e43"}
                            onMouseLeave={(e) => e.currentTarget.style.borderColor = "#e0e0e0"}
                        >
                            ← Go Back
                        </button>

                        <button
                            onClick={() => navigate("/")}
                            style={{
                                padding: "10px 22px",
                                borderRadius: 10,
                                border: "none",
                                background: "#ff3e43",
                                color: "#fff",
                                fontSize: "0.85rem",
                                fontWeight: 600,
                                cursor: "pointer",
                                transition: "all 0.2s",
                            }}
                            onMouseEnter={(e) => e.currentTarget.style.background = "#e0353a"}
                            onMouseLeave={(e) => e.currentTarget.style.background = "#ff3e43"}
                        >
                            Go to Home
                        </button>
                    </div>
                </div>

                {/* Footer note */}
                <p style={{
                    marginTop: 24,
                    fontSize: "0.78rem",
                    color: "#bbb",
                }}>
                    If you think this is a mistake, please contact support.
                </p>

            </div>
        </div>
    );
}